-- Parents of `v`: `Set Node`-valued for uniform carrier across the row (see file preamble).
def Pa (G : CDMG Node) (v : Node) : Set Node :=
  -- `w Ōłł G` uses the `Membership Node (CDMG Node)` instance (J Ōł¬ V); kept for LN parity.
  {w | w Ōłł G Ōł¦ (w, v) Ōłł G.E}

-- Children of `v`: mirror of `Pa G v` with edge direction reversed.
def Ch (G : CDMG Node) (v : Node) : Set Node :=
  -- `(v, w) Ōłł G.E` is the only swap from `Pa`; `w Ōłł G` kept for LN parity (see `Pa`).
  {w | w Ōłł G Ōł¦ (v, w) Ōłł G.E}

-- Siblings of `v`: nodes joined to `v` by a bidirected edge; no `SibSet` form (LN omits it).
def Sib (G : CDMG Node) (v : Node) : Set Node :=
  -- `s(v, w)` is `Sym2.mk (v, w)`; equals `s(w, v)` definitionally, so symmetry is free.
  -- `w Ōłł G` kept for LN parity (see `Pa`); `v Ōłē Sib G v` follows from `hL_irrefl` + `Sym2.IsDiag`.
  {w | w Ōłł G Ōł¦ s(v, w) Ōłł G.L}

-- Ancestors of `v`: nodes admitting a directed walk to `v` (any length, including 0).
def Anc (G : CDMG Node) (v : Node) : Set Node :=
  -- `Walk G w v` from `def_3_4`; `IsDirectedWalk` is a predicate, not a separate inductive.
  -- Length-0 `Walk.nil` makes `v Ōłł Anc G v` unconditional (no self-loop required).
  {w | w Ōłł G Ōł¦ Ōłā p : Walk G w v, p.IsDirectedWalk}

-- Descendants of `v`: mirror of `Anc` with `Walk G v w` (start at `v`, end at `w`).
def Desc (G : CDMG Node) (v : Node) : Set Node :=
  -- Same `IsDirectedWalk` predicate; `Walk.nil` again gives unconditional `v Ōłł Desc G v`.
  {w | w Ōłł G Ōł¦ Ōłā p : Walk G v w, p.IsDirectedWalk}

-- District of `v`: nodes reachable by a bidirected walk (any length, including 0).
def Dist (G : CDMG Node) (v : Node) : Set Node :=
  -- Same `Walk` carrier as `Anc`/`Desc`; only the predicate switches to `IsBidirectedWalk`.
  -- `Walk.nil` gives unconditional `v Ōłł Dist G v` (no bidirected self-loop needed).
  {w | w Ōłł G Ōł¦ Ōłā p : Walk G v w, p.IsBidirectedWalk}
